insert into public.quiz_question (role_kind, category, stem, options, correct_index) values
  ('instructor','Administrative','Who registers a candidate for assessment?',array['The parent directly','The instructor or centre','The examiner','MAS reception'],1),
  ('instructor','Administrative','A candidate who is not registered on the Portal:',array['Can still be assessed on the day','Cannot be assessed','Is assessed at a discount','Registers at the poolside'],1),
  ('instructor','Administrative','The claim code you generate is:',array['Printed on the certificate','Handed to the parent to link their child''s record','The examiner''s login','Posted publicly'],1),
  ('instructor','Administrative','A new swimmer with no prior BADGES badge starts at:',array['The level the parent chooses','Starfish (Level 1)','Any level','Dolphin'],1),
  ('instructor','Governance','An examiner may assess a candidate they personally taught:',array['Yes, they know them best','No, never','Only for low levels','With parent consent'],1),
  ('instructor','Governance','The document that owns the assessment criteria is:',array['The Manual','The 7-Level Syllabus','The Teaching Handbook','The Course Guide'],1),
  ('instructor','Governance','Public certificate verification shows:',array['The child''s full name and address','That the certificate is genuine, without exposing the child''s identity','The claim code','The parent''s phone number'],1),
  ('instructor','Governance','The instructor prepares and books the assessment; who judges it?',array['The same instructor','A different, independent examiner','The parent','The centre admin'],1),
  ('instructor','Safety','Your default teaching position is:',array['In the water beside the swimmer','On the poolside where you can see everyone','Wherever is comfortable','At the deep end'],1),
  ('instructor','Safety','Before giving manual (hands-on) support you must:',array['Nothing, just support','Gain consent and explain where and how','Ask another instructor','Support under the tummy'],1),
  ('instructor','Safety','A safeguarding concern must be escalated to:',array['The parent only','The Designated Safeguarding Lead','No one','Social media'],1),
  ('instructor','Safety','The maximum in-water teaching ratio is:',array['1:10','1:6','1:20','No limit'],1),
  ('instructor','Safety','Whenever in-water teaching takes place there must be:',array['Background music','A competent responder on the poolside','Two parents present','A whistle only'],1),
  ('instructor','Safety','If thunder or lightning starts, you:',array['Finish the drill','Clear the water immediately and follow the venue''s protocol','Move to the deep end','Ignore it'],1),
  ('instructor','Safety','To act as a Water-Safety Supervisor on assessment day you must hold:',array['Nothing in particular','A current lifesaving / First Aid–CPR (or equivalent) certification','A whistle','A university degree'],1),
  ('instructor','Teaching methods','"Teaching to the test" means:',array['Building real technique so the task is easy','Drilling the exact assessment task in isolation to manufacture a pass','Following the Syllabus','Assessing often'],1),
  ('instructor','Teaching methods','IRD stands for:',array['Instruct, Repeat, Deliver','Introduce, Reinforce, Develop','Inspect, Review, Deploy','Induct, Recover, Drill'],1),
  ('instructor','Teaching methods','In the IRD model, "Reinforce" means:',array['Introduce a brand-new skill','Stabilise a skill until it is consistent and unprompted','Add competitive timing','Assess the skill'],1),
  ('instructor','Teaching methods','A swimmer''s hips and legs sink on a front float. A good first cue:',array['Kick harder','Look down, big lungs, gently press the chest','Hold the wall','Lift the head'],1),
  ('instructor','Teaching methods','Best feedback practice is to:',array['Only point out faults','Sandwich a correction between two positives, owned and specific','Say nothing','Compare to other swimmers'],1),
  ('instructor','Teaching methods','Front-crawl breathing is best taught as:',array['Lift the head to breathe','Turn the head, keeping one goggle in the water','Hold the breath throughout','Never breathe'],1),
  ('instructor','Syllabus & Rubrics','A "Refer" outcome at assessment is:',array['A failure of the instructor','A normal, useful result naming a gap to close','A reason to pressure the examiner','The end of the pathway'],1),
  ('instructor','Syllabus & Rubrics','A talented swimmer may skip a level:',array['Yes','No — levels are earned in order','Only Levels 1–3','For an extra fee'],1),
  ('instructor','Syllabus & Rubrics','A swimmer is ready for assessment when:',array['They have attended enough lessons','Every criterion at the level is met independently','They reach a certain age','The parent asks'],1),
  ('instructor','Syllabus & Rubrics','Which rubric domain is a hard gate — an automatic non-pass if not met?',array['Communication','Safety, supervision & positioning','Planning','Reward'],1),
  ('examiner','Judging & criteria','When judging a level, an examiner assesses strictly against which part of the Syllabus?',array['The Teaching Objective (left column)','The Assessment Criteria (right column)','Both columns weighted equally','The Stage Milestone summary'],1),
  ('examiner','Judging & criteria','A candidate meets six of a level''s seven criteria. The correct outcome is:',array['Pass — the majority are met','Pass with conditions','Refer — a level is awarded only when every criterion is met to standard','A partial pass, recorded criterion by criterion'],2),
  ('examiner','Judging & criteria','In Poolside Calibration, a candidate examiner''s call is measured against:',array['The candidate examiner''s own consistency across swimmers','The independent, silent agreement of the Master Trainer and Chief Examiner','The majority vote of the candidate examiners present','The opinion of the swimmer''s instructor'],1),
  ('examiner','Judging & criteria','When the Master Trainer and Chief Examiner initially split on a call during benchmarking, that swimmer-criterion is:',array['Discarded from the calibration set','Recorded automatically as a Pass','Defined as Borderline; they confer, and the resolved call becomes the benchmark','Re-swum until the two experts happen to agree'],2),
  ('examiner','Judging & criteria','The calibration bar tolerates zero over-passes on non-borderline calls because:',array['Over-passes are simply easier to detect','An over-pass certifies an unearned award — the more serious error','Under-passes never occur in practice','The Chief Examiner prefers stricter marking generally'],1),
  ('examiner','Assessment-day procedure','How many groups of candidates should be in the water per examiner at one time?',array['As many as the pool can hold','One group at a time','Two groups, to save time','Unlimited, if a supervisor is present'],1),
  ('examiner','Assessment-day procedure','The maximum number of candidates a single examiner may assess in one session is:',array['16','30','60','There is no limit'],1),
  ('examiner','Assessment-day procedure','Assessment outcomes are:',array['Announced at the poolside as each candidate finishes','Released centrally on the Portal after the examiner submits the record','Posted publicly with candidate names','Read out to each parent on the day'],1),
  ('examiner','Assessment-day procedure','Which session composition is **not** permitted?',array['Three adjacent levels in one session','Levels 6 and 7 paired in one session','A single level filling the whole session','Two adjacent levels together'],1),
  ('examiner','Assessment-day procedure','Before any candidate enters the water, the examiner must first:',array['Collect outstanding fees','Complete the pre-assessment venue and safety check','Announce the previous session''s results','Pre-sign the certificates'],1),
  ('examiner','Safety & consent gate','At the first thunder or lightning, the examiner:',array['Finishes the current level quickly, then clears the water','Clears the water immediately and follows the venue''s lightning protocol','Waits ten minutes before deciding','Continues if the rain is still light'],1),
  ('examiner','Safety & consent gate','A session cut short by weather is recorded as:',array['A Refer for the affected candidates','A rain-off; affected candidates re-book at no additional fee','A Pass by default','A cancellation with the fee forfeited'],1),
  ('examiner','Safety & consent gate','A document that must be on file before a candidate is assessed is:',array['The candidate''s birth certificate only','A Consent / Safe-to-Swim Declaration (F-SHR-01)','The instructor''s teaching log','A parent''s photo identification'],1),
  ('examiner','Safety & consent gate','On the venue safety inspection, stop-work authority belongs to:',array['Only the Chief Examiner','Only the venue operator','Anyone on deck who identifies an unsafe condition','The Session Coordinator alone'],2),
  ('examiner','Safety & consent gate','An incident or near-miss during a session must be reported:',array['Within 30 days','Only if an injury resulted','The same day','At the next annual meeting'],2),
  ('examiner','Governance & independence (COI)','The conflict-of-interest rule requires that an examiner never:',array['Assess more than one level in a day','Assess a swimmer they personally taught','Work at more than one partner centre','Assess on weekends'],1),
  ('examiner','Governance & independence (COI)','The examiner roster is owned and maintained by:',array['The Chairperson','The Master Trainer','The Chief Examiner','The Finance Officer'],2),
  ('examiner','Governance & independence (COI)','A candidate who receives a Refer may:',array['Appeal the result to the Board','Request a re-mark of the same recorded performance','Re-prepare and re-attempt at a future session — there is no result-appeal process','Demand reassessment by a different examiner on the day'],2),
  ('examiner','Governance & independence (COI)','An examiner''s initial appointment term is:',array['One year','Two years','Five years','Indefinite'],1),
  ('examiner','Governance & independence (COI)','Final ratification of a new examiner rests with:',array['The Master Trainer alone','The Coaching Panel, on the Chief Examiner''s recommendation with the Chairperson''s endorsement','The Finance Officer','The candidate''s home centre'],1),
  ('examiner','Portal (examiner role)','Accepting a session invitation in the Portal:',array['Only adds the session to the examiner''s calendar','Assigns the roster and makes those candidates gradeable by that examiner and no other','Charges the examiner a session fee','Automatically passes every candidate'],1),
  ('examiner','Portal (examiner role)','A recorded Pass in the Portal:',array['Must be printed manually by the instructor','Auto-links to a serialized, append-only certificate','Remains editable for 30 days','Is published with the candidate''s full name'],1),
  ('examiner','Portal (examiner role)','Public certificate verification in the Portal:',array['Displays the child''s full name and centre','Confirms the level and validity without exposing the minor''s identifying information','Requires the parent''s password','Is disabled entirely for child safety'],1),
  ('examiner','Portal (examiner role)','When the Portal detects that the examiner instructed a candidate on the roster, it:',array['Warns the examiner but allows the grade','Blocks that candidate from that examiner (the COI trigger)','Reassigns the entire session','Notifies the parent automatically'],1),
  ('examiner','Portal (examiner role)','A Refer recorded in the Portal must:',array['Carry its reasons — the criteria not yet met','Be limited to one per session','Include a photo of the candidate','Be approved by the booking instructor'],0);
